/**
 * 测试工具库 - 类型安全的 Mock 辅助函数
 * 
 * 解决问题：
 * 1. Jest Mock 函数类型推断错误
 * 2. 提供统一的 Mock 创建方式
 * 3. 简化测试代码编写
 */

import { jest } from '@jest/globals';

// ==================== 类型安全的 Mock 工厂 ====================

/**
 * 创建类型安全的异步 Mock 函数
 * 
 * @example
 * const mockFn = createAsyncMock<() => Promise<string>>()
 *   .mockResolvedValue('success');
 */
export function createAsyncMock<T extends (...args: any[]) => Promise<any>>(
  implementation?: T
): jest.MockedFunction<T> {
  return jest.fn(implementation) as jest.MockedFunction<T>;
}

/**
 * 创建类型安全的同步 Mock 函数
 * 
 * @example
 * const mockFn = createSyncMock<(x: number) => number>()
 *   .mockReturnValue(42);
 */
export function createSyncMock<T extends (...args: any[]) => any>(
  implementation?: T
): jest.MockedFunction<T> {
  return jest.fn(implementation) as jest.MockedFunction<T>;
}

/**
 * 创建带重试的异步 Mock（模拟网络请求等）
 * 
 * @example
 * const mockFn = createRetriableMock<() => Promise<string>>()
 *   .mockRejectedValueOnce(new Error('Network error'))
 *   .mockResolvedValueOnce('success');
 */
export function createRetriableMock<T extends (...args: any[]) => Promise<any>>(): jest.MockedFunction<T> {
  return jest.fn() as jest.MockedFunction<T>;
}

// ==================== 场景 Mock 工具 ====================

/**
 * Mock 数据库（用于 Dashboard 测试）
 */
export class MockDatabase {
  iterations: any[] = [];
  agentStates: any[] = [];
  projects: any[] = [];

  prepare = jest.fn((query: string) => {
    return {
      get: jest.fn((...params: any[]) => {
        if (query.includes('iterations')) return this.iterations[0];
        if (query.includes('agent_states')) return this.agentStates[0];
        return null;
      }),
      all: jest.fn((...params: any[]) => {
        if (query.includes('iterations')) return this.iterations;
        if (query.includes('agent_states')) return this.agentStates;
        return [];
      }),
      run: jest.fn(() => ({ changes: 1, lastInsertRowid: 1 }))
    };
  }) as any;

  get = jest.fn() as any;
  all = jest.fn() as any;
  run = jest.fn() as any;
  exec = jest.fn() as any;
  close = jest.fn() as any;
}

/**
 * Mock Claude SDK Query
 */
export function createMockQuery() {
  return createAsyncMock<any>();
}

/**
 * Mock Agent 执行场景
 */
export class MockAgentScenario {
  private mockQuery = createAsyncMock<any>();

  /**
   * 设置成功场景
   */
  success(responseText: string = 'Success') {
    this.mockQuery.mockImplementation(async function* () {
      yield {
        type: 'assistant',
        message: {
          content: [{ type: 'text', text: responseText }]
        }
      };
      yield {
        type: 'result',
        result: 'Done'
      };
    });
    return this.mockQuery;
  }

  /**
   * 设置错误场景
   */
  error(error: Error) {
    this.mockQuery.mockImplementation(async function* () {
      throw error;
    });
    return this.mockQuery;
  }

  /**
   * 设置多轮对话场景
   */
  conversation(responses: string[]) {
    let callCount = 0;
    this.mockQuery.mockImplementation(async function* () {
      const response = responses[callCount++] || 'No more responses';
      yield {
        type: 'assistant',
        message: {
          content: [{ type: 'text', text: response }]
        }
      };
      yield {
        type: 'result',
        result: response
      };
    });
    return this.mockQuery;
  }
}

// ==================== 测试辅助函数 ====================

/**
 * 创建测试用的 Agent 配置
 */
export function createTestAgentConfig(overrides?: Partial<any>): any {
  return {
    role: 'TestAgent',
    systemPrompt: 'You are a test agent',
    allowedTools: ['bash', 'edit'],
    ...overrides
  };
}

/**
 * 等待异步操作完成
 */
export async function waitFor(condition: () => boolean, timeout = 5000): Promise<void> {
  const startTime = Date.now();
  while (!condition()) {
    if (Date.now() - startTime > timeout) {
      throw new Error(`Timeout waiting for condition after ${timeout}ms`);
    }
    await new Promise(resolve => setTimeout(resolve, 50));
  }
}

/**
 * 延迟执行
 */
export function delay(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

// ==================== Jest 配置工具 ====================

/**
 * 清除所有 Mock
 */
export function clearAllMocks() {
  jest.clearAllMocks();
}

/**
 * 重置所有 Mock
 */
export function resetAllMocks() {
  jest.resetAllMocks();
}

/**
 * 恢复所有 Mock
 */
export function restoreAllMocks() {
  jest.restoreAllMocks();
}
